// OAuth Configuration
const OAUTH_CONFIG = {
  clientId: 'YOUR_CLIENT_ID',
  redirectUri: window.location.origin + '/callback',
  authorizationEndpoint: 'https://oauth-provider.com/oauth/authorize',
  tokenEndpoint: 'https://oauth-provider.com/oauth/token',
  scope: 'read write',
  clientSecret: 'YOUR_CLIENT_SECRET'
};

// Storage keys
const STORAGE_KEYS = {
  ACCESS_TOKEN: 'oauth_access_token',
  REFRESH_TOKEN: 'oauth_refresh_token',
  TOKEN_EXPIRY: 'oauth_token_expiry',
  STATE: 'oauth_state',
  CODE_VERIFIER: 'oauth_code_verifier'
};

// Utility functions
function generateRandomString(length) {
  const charset = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~';
  let result = '';
  const randomValues = new Uint8Array(length);
  crypto.getRandomValues(randomValues);
  for (let i = 0; i < length; i++) {
    result += charset[randomValues[i] % charset.length];
  }
  return result;
}

async function sha256(plain) {
  const encoder = new TextEncoder();
  const data = encoder.encode(plain);
  return crypto.subtle.digest('SHA-256', data);
}

function base64urlencode(buffer) {
  const bytes = new Uint8Array(buffer);
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary)
    .replace(/\+/g, '-')
    .replace(/\//g, '_')
    .replace(/=+$/, '');
}

async function generateCodeChallenge(verifier) {
  const hashed = await sha256(verifier);
  return base64urlencode(hashed);
}

// OAuth Service
class OAuthService {
  async initiateLogin() {
    const state = generateRandomString(32);
    const codeVerifier = generateRandomString(128);
    const codeChallenge = await generateCodeChallenge(codeVerifier);

    localStorage.setItem(STORAGE_KEYS.STATE, state);
    localStorage.setItem(STORAGE_KEYS.CODE_VERIFIER, codeVerifier);

    const params = new URLSearchParams({
      response_type: 'code',
      client_id: OAUTH_CONFIG.clientId,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      scope: OAUTH_CONFIG.scope,
      state: state,
      code_challenge: codeChallenge,
      code_challenge_method: 'S256'
    });

    window.location.href = `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
  }

  async handleCallback() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const state = urlParams.get('state');
    const error = urlParams.get('error');

    if (error) {
      throw new Error(`OAuth error: ${error}`);
    }

    const storedState = localStorage.getItem(STORAGE_KEYS.STATE);
    
    if (!state || state !== storedState) {
      throw new Error('Invalid state parameter');
    }

    if (!code) {
      throw new Error('No authorization code received');
    }

    await this.exchangeCodeForToken(code);
    
    localStorage.removeItem(STORAGE_KEYS.STATE);
    localStorage.removeItem(STORAGE_KEYS.CODE_VERIFIER);
    
    window.history.replaceState({}, document.title, window.location.pathname);
  }

  async exchangeCodeForToken(code) {
    const codeVerifier = localStorage.getItem(STORAGE_KEYS.CODE_VERIFIER);
    
    const params = new URLSearchParams({
      grant_type: 'authorization_code',
      code: code,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      client_id: OAUTH_CONFIG.clientId,
      code_verifier: codeVerifier
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new Error(`Token exchange failed: ${errorData.error || response.statusText}`);
    }

    const data = await response.json();
    this.storeTokens(data);
    return data;
  }

  storeTokens(tokenData) {
    localStorage.setItem(STORAGE_KEYS.ACCESS_TOKEN, tokenData.access_token);
    
    if (tokenData.refresh_token) {
      localStorage.setItem(STORAGE_KEYS.REFRESH_TOKEN, tokenData.refresh_token);
    }
    
    if (tokenData.expires_in) {
      const expiryTime = Date.now() + (tokenData.expires_in * 1000);
      localStorage.setItem(STORAGE_KEYS.TOKEN_EXPIRY, expiryTime.toString());
    }
  }

  getAccessToken() {
    return localStorage.getItem(STORAGE_KEYS.ACCESS_TOKEN);
  }

  getRefreshToken() {
    return localStorage.getItem(STORAGE_KEYS.REFRESH_TOKEN);
  }

  isTokenExpired() {
    const expiryTime = localStorage.getItem(STORAGE_KEYS.TOKEN_EXPIRY);
    if (!expiryTime) return true;
    return Date.now() >= parseInt(expiryTime);
  }

  isAuthenticated() {
    const token = this.getAccessToken();
    return token && !this.isTokenExpired();
  }

  async refreshAccessToken() {
    const refreshToken = this.getRefreshToken();
    
    if (!refreshToken) {
      throw new Error('No refresh token available');
    }

    const params = new URLSearchParams({
      grant_type: 'refresh_token',
      refresh_token: refreshToken,
      client_id: OAUTH_CONFIG.clientId
    });

    const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      body: params.toString()
    });

    if (!response.ok) {
      this.logout();
      throw new Error('Token refresh failed');
    }

    const data = await response.json();
    this.storeTokens(data);
    return data;
  }

  logout() {
    localStorage.removeItem(STORAGE_KEYS.ACCESS_TOKEN);
    localStorage.removeItem(STORAGE_KEYS.REFRESH_TOKEN);
    localStorage.removeItem(STORAGE_KEYS.TOKEN_EXPIRY);
    localStorage.removeItem(STORAGE_KEYS.STATE);
    localStorage.removeItem(STORAGE_KEYS.CODE_VERIFIER);
  }
}

// API Service with auto-refresh
class ApiService {
  constructor(oauthService) {
    this.oauthService = oauthService;
  }

  async fetch(url, options = {}) {
    if (!this.oauthService.isAuthenticated()) {
      if (this.oauthService.getRefreshToken()) {
        await this.oauthService.refreshAccessToken();
      } else {
        throw new Error('Not authenticated');
      }
    }

    const token = this.oauthService.getAccessToken();
    
    const headers = {
      ...options.headers,
      'Authorization': `Bearer ${token}`
    };

    let response = await fetch(url, { ...options, headers });

    if (response.status === 401) {
      try {
        await this.oauthService.refreshAccessToken();
        const newToken = this.oauthService.getAccessToken();
        headers['Authorization'] = `Bearer ${newToken}`;
        response = await fetch(url, { ...options, headers });
      } catch (error) {
        this.oauthService.logout();
        throw new Error('Authentication failed');
      }
    }

    return response;
  }

  async get(url) {
    const response = await this.fetch(url);
    return response.json();
  }

  async post(url, data) {
    const response = await this.fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(data)
    });
    return response.json();
  }

  async put(url, data) {
    const response = await this.fetch(url, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify(data)
    });
    return response.json();
  }

  async delete(url) {
    const response = await this.fetch(url, {
      method: 'DELETE'
    });
    return response.json();
  }
}

// App Component
class App {
  constructor() {
    this.oauthService = new OAuthService();
    this.apiService = new ApiService(this.oauthService);
    this.currentView = 'loading';
  }

  async init() {
    const urlParams = new URLSearchParams(window.location.search);
    
    if (urlParams.has('code')) {
      try {
        await this.oauthService.handleCallback();
        this.showDashboard();
      } catch (error) {
        console.error('OAuth callback error:', error);
        this.showLogin(error.message);
      }
    } else if (this.oauthService.isAuthenticated()) {
      this.showDashboard();
    } else if (this.oauthService.getRefreshToken()) {
      try {
        await this.oauthService.refreshAccessToken();
        this.showDashboard();
      } catch (error) {
        this.showLogin();
      }
    } else {
      this.showLogin();
    }
  }

  showLogin(errorMessage = '') {
    this.currentView = 'login';
    this.render();
    
    const loginButton = document.getElementById('loginButton');
    if (loginButton) {
      loginButton.addEventListener('click', () => {
        this.oauthService.initiateLogin();
      });
    }
  }

  async showDashboard() {
    this.currentView = 'dashboard';
    this.render();
    
    const logoutButton = document.getElementById('logoutButton');
    if (logoutButton) {
      logoutButton.addEventListener('click', () => {
        this.oauthService.logout();
        this.showLogin();
      });
    }

    const fetchDataButton = document.getElementById('fetchDataButton');
    if (fetchDataButton) {
      fetchDataButton.addEventListener('click', async () => {
        try {
          const data = await this.apiService.get('https://api.example.com/user/profile');
          document.getElementById('apiData').textContent = JSON.stringify(data, null, 2);
        } catch (error) {
          document.getElementById('apiData').textContent = `Error: ${error.message}`;
        }
      });
    }
  }

  render() {
    const appContainer = document.getElementById('app');
    
    if (this.currentView === 'loading') {
      appContainer.innerHTML = `
        <div class="container">
          <div class="loading">Loading...</div>
        </div>
      `;
    } else if (this.currentView === 'login') {
      appContainer.innerHTML = `
        <div class="container">
          <div class="login-box">
            <h1>OAuth 2.0 Authentication</h1>
            <p>Please log in to continue</p>
            <button id="loginButton" class="btn btn-primary">Login with OAuth</button>
          </div>
        </div>
      `;
    } else if (this.currentView === 'dashboard') {
      appContainer.innerHTML = `
        <div class="container">
          <div class="dashboard">
            <div class="header">
              <h1>Dashboard</h1>
              <button id="logoutButton" class="btn btn-secondary">Logout</button>
            </div>
            <div class="content">
              <p>You are successfully authenticated!</p>
              <button id="fetchDataButton" class="btn btn-primary">Fetch API Data</button>
              <pre id="apiData" class="api-data"></pre>
            </div>
          </div>
        </div>
      `;
    }
  }
}

// Initialize the app
document.addEventListener('DOMContentLoaded', () => {
  const app = new App();
  app.init();
});

